import{_ as e,c as r,o as h,a2 as t}from"./chunks/framework.CriqKoQt.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/2026上/23天战胜拖延症-黄河清.md","filePath":"docs/2026上/23天战胜拖延症-黄河清.md","lastUpdated":1777192673000}'),o={name:"docs/2026上/23天战胜拖延症-黄河清.md"};function i(l,a,n,d,s,c){return h(),r("div",null,a[0]||(a[0]=[t('<h2 id="发刊词-23天-陪你走出-拖延症怪圈" tabindex="-1">发刊词：23天，陪你走出“拖延症怪圈” <a class="header-anchor" href="#发刊词-23天-陪你走出-拖延症怪圈" aria-label="Permalink to &quot;发刊词：23天，陪你走出“拖延症怪圈”&quot;">​</a></h2><h3 id="黄和清在课程中提到了一个战胜拖延症的方法-这个方法叫什么-它的原理是什么" tabindex="-1">黄和清在课程中提到了一个战胜拖延症的方法，这个方法叫什么？它的原理是什么？ <a class="header-anchor" href="#黄和清在课程中提到了一个战胜拖延症的方法-这个方法叫什么-它的原理是什么" aria-label="Permalink to &quot;黄和清在课程中提到了一个战胜拖延症的方法，这个方法叫什么？它的原理是什么？&quot;">​</a></h3><p><strong>烂开始原则。其原理是不要期望一次性完成完美的任务，而是着重于先开始</strong>，不管起初的质量如何，通过逐渐完善来完成任务。这个原则帮助人们突破由于追求完美而导致的拖延，慢慢从写几句话、做一小步开始，逐步推进以实现任务的最终完成。即便开始的部分不完美，这种方法也能通过不断改进，使最终成果达到较高的质量。</p><h3 id="拖延症怪圈包括几个关键节点-举一个节点并解释其表现和影响。" tabindex="-1">拖延症怪圈包括几个关键节点？举一个节点并解释其表现和影响。 <a class="header-anchor" href="#拖延症怪圈包括几个关键节点-举一个节点并解释其表现和影响。" aria-label="Permalink to &quot;拖延症怪圈包括几个关键节点？举一个节点并解释其表现和影响。&quot;">​</a></h3><p>拖延症怪圈共有五个关键节点。其中一个节点是第三个节点，当时间已过去且任务还未开始时，可能带来一种不祥的预感，这时人们常想要逃避，认为“不开始又能怎么样呢？”结果是循环拖延，让人无法摆脱拖延症的困境，进而沉浸在对自己浪费时间的责备中，转而做其他无关紧要的事情，比如刷网页或外出玩，最终积压了更多任务。</p><img src="https://cdn.uwayfly.com/article/2026/4/own_mike_4fa8NBPYY8cSyNxA.png" width="700"><h3 id="黄和清介绍的课程内容分为哪三大模块-每个模块的主要内容是什么" tabindex="-1">黄和清介绍的课程内容分为哪三大模块？每个模块的主要内容是什么？ <a class="header-anchor" href="#黄和清介绍的课程内容分为哪三大模块-每个模块的主要内容是什么" aria-label="Permalink to &quot;黄和清介绍的课程内容分为哪三大模块？每个模块的主要内容是什么？&quot;">​</a></h3><p>课程分为三大模块。第一模块介绍战胜拖延症的方程式，涉及改变拖延行为的四个核心问题。第二模块是实战训练，涵盖如何在工作和生活中抵御拖延。从<strong>改变习惯、任务管理、自我激励、提升专注力到时间管理</strong>，提供系统的方法来建立节奏。第三模块是进阶部分，讲解人本身的管理方法，比如通过运动管理注意力和通过正念冥想来放松身心提升专注力，提供个性化练习，帮助学员进阶掌控拖延。</p><h2 id="_01认识拖延症-是什么让你不受控制地拖" tabindex="-1">01认识拖延症，是什么让你不受控制地拖 <a class="header-anchor" href="#_01认识拖延症-是什么让你不受控制地拖" aria-label="Permalink to &quot;01认识拖延症，是什么让你不受控制地拖&quot;">​</a></h2><h3 id="如何判断自己是否有拖延症" tabindex="-1">如何判断自己是否有拖延症？ <a class="header-anchor" href="#如何判断自己是否有拖延症" aria-label="Permalink to &quot;如何判断自己是否有拖延症？&quot;">​</a></h3><p>拖延症判断的依据主要包括以下四个标准：第一，你是否认为拖延的事情会对自己未来造成严重的不良后果；第二，这种焦虑又没有行动的状态会不会让你感到痛苦；第三，你是否明知道要做的事情很重要，拖延不好，但依旧无法停止拖延；第四，拖延是否给你的人际关系造成了紧张，或者让你在乎的人困扰。如果四条都不符合，你的拖延不被自己和周围的人视作问题，那么这只是生活的一部分，不是拖延症；若符合这四条标准，则需要进行调整。</p><h3 id="解释一下改变拖延症的行动方程式及其要点。" tabindex="-1">解释一下改变拖延症的行动方程式及其要点。 <a class="header-anchor" href="#解释一下改变拖延症的行动方程式及其要点。" aria-label="Permalink to &quot;解释一下改变拖延症的行动方程式及其要点。&quot;">​</a></h3><p>改变拖延症的行动方程式是由加拿大心理学家皮尔斯·斯蒂尔总结的，它表述为：<strong>改变动力=（期望×价值感）÷（冲动×推迟）</strong>。‘期望’指的是你对任务成功完成的信心，以及对成果的预期；‘价值感’指的是你觉得这件事对你有多重要和有益；‘冲动’指的是你有多容易因为诱惑而分心；‘推迟’是指你把完成任务的行为拖延到遥远的未来。期望和价值感越高，冲动和推迟越低，你就越有动力去做一件事，反之则容易陷入拖延。</p><h3 id="举例说明-期望-和-价值感-如何影响一个人的行动动力" tabindex="-1">举例说明‘期望’和‘价值感’如何影响一个人的行动动力？ <a class="header-anchor" href="#举例说明-期望-和-价值感-如何影响一个人的行动动力" aria-label="Permalink to &quot;举例说明‘期望’和‘价值感’如何影响一个人的行动动力？&quot;">​</a></h3><p>‘期望’和‘价值感’的高低直接影响一个人的行动动力。例如：如果你特别喜欢吃烤羊腿，且认为吃到烤羊腿会让你非常快乐（高价值感），加上你觉得获得烤羊腿是完全在掌控之中的事情（高期望），你就会有很大的动力去吃烤羊腿。反之，如果你不认同某份工作的价值，并且觉得自己能力不足，无法做到，这会导致你的期望和价值感都很低，从而导致拖延。所以当期望和价值感高时，行动动力就大；当它们低时，行动动力就小。</p><h2 id="_02调整自我期望-克服拖延的心理障碍" tabindex="-1">02调整自我期望，克服拖延的心理障碍 <a class="header-anchor" href="#_02调整自我期望-克服拖延的心理障碍" aria-label="Permalink to &quot;02调整自我期望，克服拖延的心理障碍&quot;">​</a></h2><h3 id="拖延症的改变公式是什么" tabindex="-1">拖延症的改变公式是什么？ <a class="header-anchor" href="#拖延症的改变公式是什么" aria-label="Permalink to &quot;拖延症的改变公式是什么？&quot;">​</a></h3><p>改变的动力等于期望乘以价值感的成绩除以冲动乘以推迟的成绩。这个公式告诉我们，能否克服拖延症与对任务的期望、价值感、冲动和时间管理有直接联系。只要相信自己能完成任务，认为任务有价值，并能克制分心，有时间紧迫感，就能增加动力，最终战胜拖延。</p><h3 id="对成功的恐惧有哪两个主要原因" tabindex="-1">对成功的恐惧有哪两个主要原因？ <a class="header-anchor" href="#对成功的恐惧有哪两个主要原因" aria-label="Permalink to &quot;对成功的恐惧有哪两个主要原因？&quot;">​</a></h3><p><strong>人们之所以对成功有恐惧，主要有两个原因：一个是自我妨碍机制，另一个是对成功的错误认识</strong>。<strong>自我妨碍机制是一种认知策略和自我保护，避免将失败归因到自身能力上。而对成功的错误认识则是认为成功需要的付出远超自己能够承受的范围，担心为了成功会失去生活的平衡和健康，从而通过拖延来降低成功的机会</strong>。</p><h3 id="如何通过调整心态重新认识成功-来解决对成功的恐惧" tabindex="-1">如何通过调整心态重新认识成功，来解决对成功的恐惧？ <a class="header-anchor" href="#如何通过调整心态重新认识成功-来解决对成功的恐惧" aria-label="Permalink to &quot;如何通过调整心态重新认识成功，来解决对成功的恐惧？&quot;">​</a></h3><p>要解决对成功的恐惧，可以通过调整心态，将固态心态转变为成长心态，关注过程中小目标的达成，而不是单纯结果。首先，相信能力可以通过努力提升，而不是固定不变。其次，选择正确的内心学习模板，远离总让你感觉挫败的人，找到真正希望你好的朋友。最后，通过及时追随小目标，不断积累正向的鼓励，增强自信心。</p><h2 id="_03给工作以价值-由被动忙碌到主动掌控" tabindex="-1">03给工作以价值，由被动忙碌到主动掌控 <a class="header-anchor" href="#_03给工作以价值-由被动忙碌到主动掌控" aria-label="Permalink to &quot;03给工作以价值，由被动忙碌到主动掌控&quot;">​</a></h2><h3 id="为什么对任务的价值感低会导致拖延行为" tabindex="-1">为什么对任务的价值感低会导致拖延行为？ <a class="header-anchor" href="#为什么对任务的价值感低会导致拖延行为" aria-label="Permalink to &quot;为什么对任务的价值感低会导致拖延行为？&quot;">​</a></h3><p>当我们认为某项任务的价值感低时，我们的脑中奖赏效应不会被触发。英国和德国的研究人员发现，当任务具有较高的奖赏时，参与者的准确率更高，这是由于高价值任务会刺激大脑分泌多巴胺，使大脑更加活跃，促使我们愿意完成任务。因此，对低价值任务没有好感，自然而然就会拖延。人们不愿处理那些没有明显奖励的枯燥工作，比如工作日志、客户资料和阅读报表。这种对任务价值感的低评价使得我们更倾向于推迟处理这些任务。</p><h3 id="如何通过提升工作的价值感来克服拖延" tabindex="-1">如何通过提升工作的价值感来克服拖延？ <a class="header-anchor" href="#如何通过提升工作的价值感来克服拖延" aria-label="Permalink to &quot;如何通过提升工作的价值感来克服拖延？&quot;">​</a></h3><p>提升工作的价值感是克服拖延的重要方法。首先，需要重新审视面对的任务，放下对抗情绪。例如，如果要加班写策划，可以看作是表现自己的机会，好的策划会让领导对你另眼相看。就像李孝来老师在背两万个单词时，重新计算背一万个单词相当于拿到年薪百万的工作，每背一个单词值五十块钱，这让他觉得任务有了很高的价值，从而不再痛苦并且高效完成任务。因此，通过重新赋予任务价值，我们可以减轻对任务的抵触情绪，进而高效完成任务。</p><h3 id="如何通过纳入计划和复述任务来获得掌控感并克服拖延" tabindex="-1">如何通过纳入计划和复述任务来获得掌控感并克服拖延？ <a class="header-anchor" href="#如何通过纳入计划和复述任务来获得掌控感并克服拖延" aria-label="Permalink to &quot;如何通过纳入计划和复述任务来获得掌控感并克服拖延？&quot;">​</a></h3><p>通过将任务纳入自己的计划并详细复述任务，可以获得掌控感并克服拖延。当任务由别人分配时，会感到被动；但一旦任务纳入自己的计划，并且详细复述任务的三个部分：接下来要怎么做、要做什么准备、找什么人，这就会产生一种自我主导的感觉。例如，完成年终总结时，可以复述为：先列出框架、收集相关数据、与相关部门联系。这种详细复述帮助暗示任务主导者是自己，增强控制感，使得任务不再是苦差事，而是自己的计划，进而更愿意立即去完成它。</p><h2 id="_04工作总是分心-与其用对抗-不如用-诱导" tabindex="-1">04工作总是分心？与其用对抗，不如用“诱导” <a class="header-anchor" href="#_04工作总是分心-与其用对抗-不如用-诱导" aria-label="Permalink to &quot;04工作总是分心？与其用对抗，不如用“诱导”&quot;">​</a></h2><h3 id="什么是分心拖延-为什么大脑的不同系统会影响我们的拖延行为" tabindex="-1">什么是分心拖延，为什么大脑的不同系统会影响我们的拖延行为？ <a class="header-anchor" href="#什么是分心拖延-为什么大脑的不同系统会影响我们的拖延行为" aria-label="Permalink to &quot;什么是分心拖延，为什么大脑的不同系统会影响我们的拖延行为？&quot;">​</a></h3><p>分心拖延是指人们通过做其他较容易的事情来逃避核心困难任务的现象，因为核心任务更难，更让人焦虑。大脑中的前额业像企业的CEO，负责长远目标和自我控制，而边缘系统像个婴儿，主导本能和情感。由于边缘系统是早期进化的产物，比前额业根深蒂固，它往往在面对冲突时占据优势，导致我们更容易选择即时的快乐而忽视长远目标。</p><h3 id="为了对抗分心拖延-课程中提到的建立仪式感的方法是什么-可以提供一些具体例子吗" tabindex="-1">为了对抗分心拖延，课程中提到的建立仪式感的方法是什么？可以提供一些具体例子吗？ <a class="header-anchor" href="#为了对抗分心拖延-课程中提到的建立仪式感的方法是什么-可以提供一些具体例子吗" aria-label="Permalink to &quot;为了对抗分心拖延，课程中提到的建立仪式感的方法是什么？可以提供一些具体例子吗？&quot;">​</a></h3><p>建立仪式感的方法包括通过使用自己喜欢的东西来诱导开始工作，例如采用舒适的工作环境或者使用喜欢的工具。具体例子有：带着自己喜欢的音乐耳机工作、用自己喜欢的书写工具、在办公桌上放一株喜欢的绿植、去喜欢的咖啡店加班，或者泡一杯喜欢的茶再开始工作。这些仪式感能够通过自我暗示提升专注力，并哄骗大脑的边缘系统接受工作任务。</p><h3 id="在听音乐工作时-有哪些注意事项" tabindex="-1">在听音乐工作时，有哪些注意事项？ <a class="header-anchor" href="#在听音乐工作时-有哪些注意事项" aria-label="Permalink to &quot;在听音乐工作时，有哪些注意事项？&quot;">​</a></h3><p>听音乐工作时需要注意：1. 简单重复的任务可以听欢快节奏的音乐，能提升效率；复杂创造性的任务则在开始前或休息时听音乐，不要在重要思考时听。2. 听没有歌词或不熟悉语言的音乐，避免流行歌曲带来的多任务干扰。3. 调低音量并尽量选择单曲循环，避免音乐切换对注意力的干扰。总体而言，听音乐可以诱导我们开始工作，但实际过程中要根据任务复杂程度和个人习惯调整。</p><h2 id="_05时间紧任务重-是你突破自己的机会" tabindex="-1">05时间紧任务重？是你突破自己的机会 <a class="header-anchor" href="#_05时间紧任务重-是你突破自己的机会" aria-label="Permalink to &quot;05时间紧任务重？是你突破自己的机会&quot;">​</a></h2><h3 id="什么是未来折扣" tabindex="-1">什么是未来折扣？ <a class="header-anchor" href="#什么是未来折扣" aria-label="Permalink to &quot;什么是未来折扣？&quot;">​</a></h3><p><strong>未来折扣是行为经济学中的一个概念，它说明了未来的收益因为距离现在的时间越长而变得越不重要</strong>。举例来说，如果你赢得了一万元奖金，你可以选择立即拿到一万元现金，或者选择一张一年后兑现的一万元支票。大多数人会选择现金而不愿意等待，这说明随着时间延长，未来收益在我们眼中的价值就会打折扣。这与推迟性拖延有关，即因为任务截止日期还很遥远，我们会觉得没有那么紧迫，从而容易拖延。</p><h3 id="计划谬误是怎样影响我们时间估算的" tabindex="-1">计划谬误是怎样影响我们时间估算的？ <a class="header-anchor" href="#计划谬误是怎样影响我们时间估算的" aria-label="Permalink to &quot;计划谬误是怎样影响我们时间估算的？&quot;">​</a></h3><p>**计划谬误是诺贝尔奖得主丹尼尔·卡尼曼提出的概念，它说明了人在规划任务时，往往会低估完成任务所需要的时间。**即使非拖延症患者也倾向于更乐观地看待自己能完成的任务，从而产生“未来有时间，现阶段可以忙别的”的错觉。比如，我们总觉得周末有更多的时间学习或工作，但实际上我们用在工作的时间可能甚至比工作日还少。因此，计划谬误导致我们错估自己完成任务的能力和时间，最终导致拖延。</p><h3 id="吉田岁波用了哪些方法来有效管理时间并实现她的目标" tabindex="-1">吉田岁波用了哪些方法来有效管理时间并实现她的目标？ <a class="header-anchor" href="#吉田岁波用了哪些方法来有效管理时间并实现她的目标" aria-label="Permalink to &quot;吉田岁波用了哪些方法来有效管理时间并实现她的目标？&quot;">​</a></h3><p>吉田岁波采取了几种方法来有效管理时间并实现她的目标。首先，她强调不要等到精心准备之后再行动，而是要在有冲动时立即开始，否则动力会随时间消退。其次，她利用零碎时间来处理不需要高度专注的任务，例如做家务时听学习音频。第三，她善于化压力为动力，在限制下反而更能高效工作，因为压力能让她更加专注。通过这些方法，她能够同时兼顾工作、家庭和学习，最终在繁忙中实现了多项目标。</p><h2 id="_06第一周小结-找到计划和现实的黄金平衡点" tabindex="-1">06第一周小结：找到计划和现实的黄金平衡点 <a class="header-anchor" href="#_06第一周小结-找到计划和现实的黄金平衡点" aria-label="Permalink to &quot;06第一周小结：找到计划和现实的黄金平衡点&quot;">​</a></h2><h3 id="为什么你会因为害怕成功而拖延" tabindex="-1">为什么你会因为害怕成功而拖延？ <a class="header-anchor" href="#为什么你会因为害怕成功而拖延" aria-label="Permalink to &quot;为什么你会因为害怕成功而拖延？&quot;">​</a></h3><p>你会因为害怕成功而拖延，是因为对结果的不确定和恐惧使你产生了一种自我妨碍机制。你可能担心成功后带来的责任或期望，甚至潜意识里会因为害怕结果的到来而下意识地设置障碍，通过拖延来降低成功的可能性。这种现象表明，你对结果的恐惧超过了对过程的兴趣。因此，通过调整期望，比如学会成长心态、重新思考自己的定位以及远离那些让你降低自我评价的朋友，可以帮助你摆脱这种自我妨碍机制。</p><h3 id="如何用计划赋予任务价值感并获得控制感" tabindex="-1">如何用计划赋予任务价值感并获得控制感？ <a class="header-anchor" href="#如何用计划赋予任务价值感并获得控制感" aria-label="Permalink to &quot;如何用计划赋予任务价值感并获得控制感？&quot;">​</a></h3><p>为了赋予任务价值感并获得控制感，你可以通过重新评估工作和任务的意义，给它们赋予新的价值。如果发现任务实际上很有意义，那就认真对待，并使用一些技巧来提升它们的价值感。再者，通过制定计划，将被动接受的任务变成主动要完成的事情。做计划能够让你更有掌控感，而这种掌控感是克服拖延的大敌。计划中的任务会变得更有价值，因为你主动选择去完成它们，从而不会再用拖延来表达反抗和虚假的控制感。</p><h3 id="为什么任务的难度与积极性之间的平衡点对抗拖延很重要" tabindex="-1">为什么任务的难度与积极性之间的平衡点对抗拖延很重要？ <a class="header-anchor" href="#为什么任务的难度与积极性之间的平衡点对抗拖延很重要" aria-label="Permalink to &quot;为什么任务的难度与积极性之间的平衡点对抗拖延很重要？&quot;">​</a></h3><p>任务的难度与积极性之间的平衡点非常重要，因为它直接影响到你的动力。如果任务太简单，就会变得无趣无味，导致积极性很低；而如果任务太难，超出了你的能力范围，你就会觉得无法完成，从而失去积极性。最适中的任务难度——跳一跳能够达到的位置，既不会过于简单而无聊，也不会过于困难而令人丧失信心，因此能让你保持最佳的动力和积极性。当计划中的任务难度适中时，你会更有动力去完成它，从而达到对抗拖延的目的。找到这个平衡点能够使你持续保持高效和积极的状态，避免因为任务太容易或太难而产生拖延。</p><h2 id="_07改变习惯-记录你的拖延行为" tabindex="-1">07改变习惯，记录你的拖延行为 <a class="header-anchor" href="#_07改变习惯-记录你的拖延行为" aria-label="Permalink to &quot;07改变习惯，记录你的拖延行为&quot;">​</a></h2><h3 id="如何更有效地记录你的拖延行为-为什么这是战胜拖延症的第一步" tabindex="-1">如何更有效地记录你的拖延行为，为什么这是战胜拖延症的第一步？ <a class="header-anchor" href="#如何更有效地记录你的拖延行为-为什么这是战胜拖延症的第一步" aria-label="Permalink to &quot;如何更有效地记录你的拖延行为，为什么这是战胜拖延症的第一步？&quot;">​</a></h3><p>有效地记录拖延行为需要注意三个层次：一是分清哪些是拖延行为，不要漏记；二是在多次记录拖延行为之后，要记住自己拖延的征兆，一出现苗头立即打住；三是记录拖延借口，不要害怕揭穿自己。记下这些行为的目的是为了意识到做了哪些事情是有必要的，哪些是没有必要的，从而慢慢戒掉拖延的习惯。通过记录拖延行为，你能够揪出那些藏得很深的拖延策略，并且反省自己一天的行为，从而更加清楚地了解自己实际的时间利用情况。这是战胜拖延症的第一步。</p><h3 id="拖延征兆分为哪几种-如何识别并阻止拖延行为的发生" tabindex="-1">拖延征兆分为哪几种？如何识别并阻止拖延行为的发生？ <a class="header-anchor" href="#拖延征兆分为哪几种-如何识别并阻止拖延行为的发生" aria-label="Permalink to &quot;拖延征兆分为哪几种？如何识别并阻止拖延行为的发生？&quot;">​</a></h3><p>拖延征兆可以大致分为三种：磨磨蹭蹭、自我拉扯和生理反应。磨磨蹭蹭指的是做一些看似相关但无关紧要的事，比如反复修改已经完成的部分而不愿意开始新的任务。自我拉扯是指脑子里有理性的前额叶和边缘系统的冲突，比如想做正事但又被冲动拖住的情况。生理反应指的是拖延时产生的身体不适，比如腰酸背痛、想上厕所等。这些征兆通常都遵循自动化的模式，一旦启动就会形成系列行为。识别这些征兆的方法是多次记录自己的拖延行为，发现其中规律，然后在这些征兆出现时，对自己拉响警报，迅速采取行动阻止拖延行为的蔓延。一个有效的方法是使用执行意图，比如制定‘如果...就...’的句式来应对拖延行为。</p><h3 id="如何处理自己在拖延时找的借口-为什么坦然面对借口很重要" tabindex="-1">如何处理自己在拖延时找的借口，为什么坦然面对借口很重要？ <a class="header-anchor" href="#如何处理自己在拖延时找的借口-为什么坦然面对借口很重要" aria-label="Permalink to &quot;如何处理自己在拖延时找的借口，为什么坦然面对借口很重要？&quot;">​</a></h3><p>处理拖延时找的借口的方法是记录并揭穿这些借口。每次拖延时，详细记录下自己拖延的行为和找的借口，比如‘查看叉叉攻略，因为今天大结局了，不去健身，因为太累了，昨天运动过了’等。每日查看这些记录，会感觉到不好意思，但这有助于你认识到自己的自我欺骗行为，从而不再继续用这些借口掩饰拖延。同时，在记录时要遵循三不原则：不评判、不指责、不欺瞒，接受客观现状，然后尝试改变。坦然面对自己的借口能让你更加真实地了解自己的习惯和心态，这是战胜拖延症的关键步骤，只有敢于面对自己，才能够有勇气改变自己的拖延行为。</p><h2 id="_08任务管理-把任务拆的可衡量" tabindex="-1">08任务管理，把任务拆的可衡量 <a class="header-anchor" href="#_08任务管理-把任务拆的可衡量" aria-label="Permalink to &quot;08任务管理，把任务拆的可衡量&quot;">​</a></h2><h3 id="什么是smart原则-它包括哪五个要素" tabindex="-1">什么是SMART原则，它包括哪五个要素？ <a class="header-anchor" href="#什么是smart原则-它包括哪五个要素" aria-label="Permalink to &quot;什么是SMART原则，它包括哪五个要素？&quot;">​</a></h3><p>SMART原则是用于制定和评估任务目标的一种方法论，它包括五个要素：具体 (Specific)，可衡量 (Measurable)，可操作 (Attainable)，相关 (Relevant)，有时间限制 (Timebound)。具体的任务目标意味着要明确具体内容，避免模棱两可；可衡量是指目标应有明确的衡量标准；可操作表明目标应是现实且可实现的；相关表示目标应与最终任务紧密相关；有时间限制则要求任务目标有明确的时间期限，避免无限拖延。</p><h3 id="为什么很多人在执行任务时会失败-并且容易拖延、低效" tabindex="-1">为什么很多人在执行任务时会失败，并且容易拖延、低效？ <a class="header-anchor" href="#为什么很多人在执行任务时会失败-并且容易拖延、低效" aria-label="Permalink to &quot;为什么很多人在执行任务时会失败，并且容易拖延、低效？&quot;">​</a></h3><p>很多人在执行任务时会失败的原因主要有三个：首先，任务目标太难，几乎不可执行；其次，任务的安排和进度管理失控，导致拖延、低效、无结果；最后，缺乏针对性的复盘反馈。要成功完成任务，需要优化任务的拆解、合理的计划和可执行的进度安排，同时进行及时的复盘和调整，以确保任务进展顺利。</p><h3 id="任务管理流程中-smart原则是如何帮助拆解目标和进行复盘反馈的" tabindex="-1">任务管理流程中，SMART原则是如何帮助拆解目标和进行复盘反馈的？ <a class="header-anchor" href="#任务管理流程中-smart原则是如何帮助拆解目标和进行复盘反馈的" aria-label="Permalink to &quot;任务管理流程中，SMART原则是如何帮助拆解目标和进行复盘反馈的？&quot;">​</a></h3><p>在任务管理流程中，SMART原则帮助拆解目标时，通过具体化任务目标，让你明确细化每个步骤，确保任务可衡量、可操作且相关。同时，设定明确的时间期限，避免拖延。在进行复盘反馈时，SMART原则通过五个要素帮助你评估和修正任务执行情况，具体评估拆解的任务目标是否明确可行，是否有明确的衡量标准，计划是否现实可达成，任务执行过程中是否保持相关，是否设定了合理的时间期限，从而有效提升任务管理效果。</p><h3 id="如何运用smart原则制定一个健康减肥计划" tabindex="-1">如何运用SMART原则制定一个健康减肥计划？ <a class="header-anchor" href="#如何运用smart原则制定一个健康减肥计划" aria-label="Permalink to &quot;如何运用SMART原则制定一个健康减肥计划？&quot;">​</a></h3><p>运用SMART原则制定健康减肥计划时，可以将总目标具体到可操作的小目标。例如，将“大目标减掉20斤”分解为“每月减6斤”。具体的饮食管理、运动安排和睡眠计划也需要列详细，如每天沿食谱饮食、每周运动多少小时、每天几点睡觉起床。每个目标要具体、可量化，防止模糊不清，以便随时考量进展。此外计划要现实可行，按饮食、运动、睡眠的细化部分进行安排，确保每个小目标与健康减肥紧密相关并有明确的时间节点确保按时完成。例如每周六称体重，定期分析进展情况，及时调整策略。</p><h2 id="_09自我激励1-成功螺旋法-建立你的自信" tabindex="-1">09自我激励1：成功螺旋法，建立你的自信 <a class="header-anchor" href="#_09自我激励1-成功螺旋法-建立你的自信" aria-label="Permalink to &quot;09自我激励1：成功螺旋法，建立你的自信&quot;">​</a></h2><h3 id="如何通过成功螺旋法激发自信并不断挑战更难的任务" tabindex="-1">如何通过成功螺旋法激发自信并不断挑战更难的任务？ <a class="header-anchor" href="#如何通过成功螺旋法激发自信并不断挑战更难的任务" aria-label="Permalink to &quot;如何通过成功螺旋法激发自信并不断挑战更难的任务？&quot;">​</a></h3><p>成功螺旋法的核心在于设定可达到的阶梯上升的小目标并不断完成它们。这背后的心理学原理是，每达成一个小目标就可以获得一定的自信，这种自信能促使我们向更高的目标前进。首先，要设定一个足够小的初始目标，使你觉得微不足道，能够轻松完成。接着，每次比原计划超额完成一点点，从而积累更多的小成功感。第三，给予自己适当的回报增强动力，确保继续前行。最后，当你觉得已经养成习惯或对任务熟练时，设定下一个挑战目标。通过这种“打怪升级”的方式，不断螺旋上升，增强自信，减少拖延。</p><h3 id="在生活和工作中如何将游戏设计中的粉末任务概念应用于克服拖延" tabindex="-1">在生活和工作中如何将游戏设计中的粉末任务概念应用于克服拖延？ <a class="header-anchor" href="#在生活和工作中如何将游戏设计中的粉末任务概念应用于克服拖延" aria-label="Permalink to &quot;在生活和工作中如何将游戏设计中的粉末任务概念应用于克服拖延？&quot;">​</a></h3><p>在游戏设计中，粉末任务是指将每一个任务碎成很细小的部分，使每一部分都非常容易完成。生活和工作中也可以利用这一概念：首先，把你畏惧的大任务拆成一些小块，小到第一步就可以立即开始。这是因为阻碍你完成目标的第一件事往往是你无法开始行动。接下来，每次比原计划多完成一点点，例如从早上做一个俯卧撑开始，慢慢增加。然而，这样做还不足够，你还需要在超额完成任务时给予自己一些替代性奖励，比如工作一小时后出去散步。这种奖励不仅带来愉悦感，还能刺激多巴胺分泌，从而大大提高重复行为的可能性。</p><h3 id="为什么多领域的成功感能够相互迁移并减少拖延" tabindex="-1">为什么多领域的成功感能够相互迁移并减少拖延？ <a class="header-anchor" href="#为什么多领域的成功感能够相互迁移并减少拖延" aria-label="Permalink to &quot;为什么多领域的成功感能够相互迁移并减少拖延？&quot;">​</a></h3><p>多领域的成功感能够迁移是因为自信和成功感是可以跨领域应用的。例如，创业者通过走戈壁挑战身体极限，克服困难，最终征服沙漠，这种经历会让他在面对其他挑战时更加自信，设定更高的目标，从而更容易取得成功。同样地，让孩子参加军训或者学习一项乐器，就是为了让他们通过克服困难，达到成功，建立自信。当一个人感受到成功并建立自信时，这种心理暗示能够迁移到其他领域，在新的任务和挑战面前，更加不会拖延。通过不断积累多领域的成功感，可以全面提升自信，提高完成不同任务的效率。</p><h3 id="为什么人们容易对游戏产生兴趣-而对工作和学习缺乏兴趣" tabindex="-1">为什么人们容易对游戏产生兴趣，而对工作和学习缺乏兴趣？ <a class="header-anchor" href="#为什么人们容易对游戏产生兴趣-而对工作和学习缺乏兴趣" aria-label="Permalink to &quot;为什么人们容易对游戏产生兴趣，而对工作和学习缺乏兴趣？&quot;">​</a></h3><p>人们容易对游戏产生兴趣是因为游戏设计得更好，主要包括三个方面：目标设计、反馈和奖赏机制、心流体验。游戏通过拆分终极目标，使得任务变成一个个容易上手的粉末任务，这种设计让玩家不断完成任务，感受到进步。其次，游戏中的反馈和奖赏机制能促使玩家产生多巴胺动机，提供即时的快乐和激励。而在工作和学习中，这些激励机制往往不足，导致人们的兴趣和动力不足。</p><h3 id="如何在工作和学习中应用游戏化的反馈和奖赏机制" tabindex="-1">如何在工作和学习中应用游戏化的反馈和奖赏机制？ <a class="header-anchor" href="#如何在工作和学习中应用游戏化的反馈和奖赏机制" aria-label="Permalink to &quot;如何在工作和学习中应用游戏化的反馈和奖赏机制？&quot;">​</a></h3><p>在工作和学习中应用游戏化的反馈和奖赏机制，可以通过两个要点实现：设置奖励预期和强化程序。首先，可以给自己列一张奖励清单，提前设置好想要的奖励，提升动力完成任务。其次，在任务完成时及时奖励自己，可以用进度表或其他即时反馈机制，保持高效工作。另外，任务和奖励的匹配需要合理，确保努力与奖励成比例，防止奖励过小或过大失去激励效果。</p><h3 id="什么是多巴胺动机-如何在日常生活中运用它" tabindex="-1">什么是多巴胺动机，如何在日常生活中运用它？ <a class="header-anchor" href="#什么是多巴胺动机-如何在日常生活中运用它" aria-label="Permalink to &quot;什么是多巴胺动机，如何在日常生活中运用它？&quot;">​</a></h3><p>多巴胺动机是指在预期获得奖励的过程中，大脑产生的一种激素，使人感到快乐和期待。要在日常生活中运用多巴胺动机，可以通过设置奖励预期和强化程序两种方法。提前设定好奖励，让自己有所期待，从而激发动力完成任务；在任务完成时及时给予反馈和奖励，增强持续努力的动力。这样，通过奖励的预期和及时反馈，就可以在日常生活中激发更多的多巴胺动机，提升积极性和效率。</p><h2 id="_10自我激励2-游戏化奖赏-让工作变好玩" tabindex="-1">10自我激励2：游戏化奖赏，让工作变好玩 <a class="header-anchor" href="#_10自我激励2-游戏化奖赏-让工作变好玩" aria-label="Permalink to &quot;10自我激励2：游戏化奖赏，让工作变好玩&quot;">​</a></h2><h2 id="_11自我激励3-走出舒适区-有挑战才有心流" tabindex="-1">11自我激励3：走出舒适区，有挑战才有心流 <a class="header-anchor" href="#_11自我激励3-走出舒适区-有挑战才有心流" aria-label="Permalink to &quot;11自我激励3：走出舒适区，有挑战才有心流&quot;">​</a></h2><h3 id="人的能力圈和对世界的认知可以分为几个区域" tabindex="-1">人的能力圈和对世界的认知可以分为几个区域 <a class="header-anchor" href="#人的能力圈和对世界的认知可以分为几个区域" aria-label="Permalink to &quot;人的能力圈和对世界的认知可以分为几个区域&quot;">​</a></h3><p>三个：舒适区、学习区、恐慌区。</p><h3 id="什么是心流状态-以及如何通过调节任务难度来达到心流状态" tabindex="-1">什么是心流状态,以及如何通过调节任务难度来达到心流状态？ <a class="header-anchor" href="#什么是心流状态-以及如何通过调节任务难度来达到心流状态" aria-label="Permalink to &quot;什么是心流状态,以及如何通过调节任务难度来达到心流状态？&quot;">​</a></h3><p>心流状态是由心理学家米哈利提出的概念，它指的是一种全神贯注、沉浸其中的心理状态。为了达到心流状态，我们需要调节任务的难度：如果任务太简单，我们会感到无聊；如果任务太难，我们会感到焦虑。通过将任务的难度调节到既不太简单也不太难的水平，使之与我们的能力相匹配，我们就能够进入心流状态。这可以通过拆分复杂任务或提高简单任务的难度来实现。</p><h3 id="为什么舒适区容易导致拖延-以及如何通过走出舒适区来克服拖延" tabindex="-1">为什么舒适区容易导致拖延，以及如何通过走出舒适区来克服拖延？ <a class="header-anchor" href="#为什么舒适区容易导致拖延-以及如何通过走出舒适区来克服拖延" aria-label="Permalink to &quot;为什么舒适区容易导致拖延，以及如何通过走出舒适区来克服拖延？&quot;">​</a></h3><p>舒适区常常因为任务过于熟悉且无挑战性，使人感到无聊，从而导致拖延。要克服拖延，需要有意识地走出舒适区，进入具有一定挑战性的学习区。我们可以通过给任务增加难度，例如压缩完成时间或提高质量标准，来让自己面对新的挑战，从而激发工作热情。长期待在舒适区不利于成长，而走出舒适区则可以保持积极状态和提高工作效率。</p><h3 id="如何利用设置趋近型目标来增强行动动力-并举个例子解释趋近型目标和回避型目标的区别" tabindex="-1">如何利用设置趋近型目标来增强行动动力,并举个例子解释趋近型目标和回避型目标的区别？ <a class="header-anchor" href="#如何利用设置趋近型目标来增强行动动力-并举个例子解释趋近型目标和回避型目标的区别" aria-label="Permalink to &quot;如何利用设置趋近型目标来增强行动动力,并举个例子解释趋近型目标和回避型目标的区别？&quot;">​</a></h3><p>趋近型目标是指暗示成功的目标，而回避型目标是指暗示避免失败的目标。设置趋近型目标可以强化你的动机，让你关注积极的成就。举个例子，表白时，你应该设定的目标是“我希望他能接受我”（趋近型目标），而不是“我不想被拒绝”（回避型目标）。通过设定趋近型目标，我们能够更专注于成功的方向，减少负面情绪的干扰，从而更有动力去行动。</p><h3 id="你如何评估一项任务是在舒适区、学习区还是恐慌区" tabindex="-1">你如何评估一项任务是在舒适区、学习区还是恐慌区？ <a class="header-anchor" href="#你如何评估一项任务是在舒适区、学习区还是恐慌区" aria-label="Permalink to &quot;你如何评估一项任务是在舒适区、学习区还是恐慌区？&quot;">​</a></h3><p>评估一项任务所在的区间，首先要看自己对任务的掌握程度。如果你觉得完全可以胜任但无聊，那任务就在舒适区。如果任务有一定挑战性，但你有信心可以应对，则在学习区。如果任务难度过高让你感到焦虑甚至恐惧，则在恐慌区。举个例子，对于常规性报告，我可以在候机时完成将其变为舒适区之外的任务，通过这样的例子达到对各区间的有效评估和调节。</p><h2 id="_12第二周小结-小红花不管用-如何有效奖励自己" tabindex="-1">12第二周小结：小红花不管用，如何有效奖励自己 <a class="header-anchor" href="#_12第二周小结-小红花不管用-如何有效奖励自己" aria-label="Permalink to &quot;12第二周小结：小红花不管用，如何有效奖励自己&quot;">​</a></h2><h3 id="如何通过自省帮助自己战胜拖延症" tabindex="-1">如何通过自省帮助自己战胜拖延症? <a class="header-anchor" href="#如何通过自省帮助自己战胜拖延症" aria-label="Permalink to &quot;如何通过自省帮助自己战胜拖延症?&quot;">​</a></h3><p>自省是战胜拖延症的重要环节，首先是对自己情况的认识，通过记录拖延行为，找出拖延征兆，揭穿拖延借口来进行自我观察。具体步骤包括观察自己，辨别哪些是拖延行为，对照摸摸蹭蹭、自我拉扯、生理反应三种征兆进行分析并记录下来。同时，按照执行意图的办法，给大脑设置一个行为线索，提醒自己不拖延。通过客观记录拖延的理由，勇敢面对自己，并且进行修正。自省还包括使用SMART原则来拆分目标，并对任务的执行状况进行反馈和评估，从而帮助更好地达成目标。</p><h3 id="如何通过游戏化的方法促进工作和学习的积极性" tabindex="-1">如何通过游戏化的方法促进工作和学习的积极性? <a class="header-anchor" href="#如何通过游戏化的方法促进工作和学习的积极性" aria-label="Permalink to &quot;如何通过游戏化的方法促进工作和学习的积极性?&quot;">​</a></h3><p>游戏化的方法通过成功螺旋法和设定奖励机制来提升工作和学习的积极性。成功螺旋法教我们积极尝试不同的支线任务，把困难的主线任务分解成易于完成的小任务，逐步提升综合实力和信心。设定与任务难度相匹配且吸引人的奖励，使枯燥的过程变得有意义和有趣。此外，扩大舒适区类似于升级换地图，增添新的挑战增加探索的乐趣。通过设定趋近型目标，可以更好地面对新的挑战，从而不断提升自己的能力和信心。</p><h3 id="如何找到适合自己的奖励机制" tabindex="-1">如何找到适合自己的奖励机制? <a class="header-anchor" href="#如何找到适合自己的奖励机制" aria-label="Permalink to &quot;如何找到适合自己的奖励机制?&quot;">​</a></h3><p>找到适合自己的奖励机制，首先要明确自己真正渴望的事情、物品或活动。奖励机制是否有效，取决于你多想要这个奖励。适当的奖励可以从小时候老师发的小红花，到学习成绩排名的提升，再到成年后的追求。比如说每天处理完工作后看一本书，这对于知识爱好者来说就是一种很好的放松和奖励。奖励的形式应随着自身的成长而变化，并且要确保奖励带来的满足感足以激发和维持长期的动力。奖励的设计不仅要符合个人兴趣，还要即时反馈，增强动力。</p><h2 id="_13提升专注1-集中注意力-营造好工作的-场" tabindex="-1">13提升专注1：集中注意力，营造好工作的“场” <a class="header-anchor" href="#_13提升专注1-集中注意力-营造好工作的-场" aria-label="Permalink to &quot;13提升专注1：集中注意力，营造好工作的“场”&quot;">​</a></h2><h3 id="什么是注意力以及它由哪些要素构成" tabindex="-1">什么是注意力以及它由哪些要素构成？ <a class="header-anchor" href="#什么是注意力以及它由哪些要素构成" aria-label="Permalink to &quot;什么是注意力以及它由哪些要素构成？&quot;">​</a></h3><p>注意力是心理活动对某一事物的集中和指向。它主要由两个要素构成：第一是注意的对象，第二是心理活动对这个对象的指向和集中。在心理学研究中，注意力可以通过环境的变化或者外部刺激（如老师的提醒）来控制和调动，从而集中在特定的任务上。</p><h3 id="如何通过环境的布置来提升注意力" tabindex="-1">如何通过环境的布置来提升注意力？ <a class="header-anchor" href="#如何通过环境的布置来提升注意力" aria-label="Permalink to &quot;如何通过环境的布置来提升注意力？&quot;">​</a></h3><p>通过对环境进行合理的功能区域划分，可以有效提升注意力。比如，可以将卧室仅用于休息，将客厅用于放松，而设置一个单独的工作区仅用于工作。这样的环境布置能够帮助大脑在不同区域自动切换到相应的状态，更容易集中注意力。</p><h3 id="什么是用仪式感强化行为的办法" tabindex="-1">什么是用仪式感强化行为的办法？ <a class="header-anchor" href="#什么是用仪式感强化行为的办法" aria-label="Permalink to &quot;什么是用仪式感强化行为的办法？&quot;">​</a></h3><p>用小行为建立起开工前的仪式感可以强化注意力。这些小行为如列诸如列出当天的工作清单、关闭不相关的网页、戴上耳机等，能够告诉大脑即将进入工作状态，并在这个过程中清理杂念，让大脑专注于眼前的任务。</p><h3 id="为什么他人的监督可以帮助提升专注力" tabindex="-1">为什么他人的监督可以帮助提升专注力？ <a class="header-anchor" href="#为什么他人的监督可以帮助提升专注力" aria-label="Permalink to &quot;为什么他人的监督可以帮助提升专注力？&quot;">​</a></h3><p>他人的监督可以提供外部压力和提醒，帮助克服分心和拖延。通过告知亲近的朋友或家人你需要完成的任务和期限，他们可以在你松懈时给予适当的提醒和督促。如果未能完成，还可以设立一定的惩罚措施，这种外部压力能够有效激励你更专注地完成任务。</p><h2 id="_14提升专注2-节约注意力-用得少就是高效" tabindex="-1">14提升专注2：节约注意力，用得少就是高效 <a class="header-anchor" href="#_14提升专注2-节约注意力-用得少就是高效" aria-label="Permalink to &quot;14提升专注2：节约注意力，用得少就是高效&quot;">​</a></h2><h3 id="为什么注意力资源是有限的" tabindex="-1">为什么注意力资源是有限的？ <a class="header-anchor" href="#为什么注意力资源是有限的" aria-label="Permalink to &quot;为什么注意力资源是有限的？&quot;">​</a></h3><p>注意力资源有限是因为我们的生理和心理能量是有限的。调动和集中注意力的过程会消耗这些能量，因此我们应当合理分配注意力资源，将其投入到重要的任务上，而不是分散在各种琐事和干扰上。丹尼尔·卡尼曼在《思考快与慢》中也指出，注意力资源的分配可以看作是对有定量限制的资源和能量的分配，每增加一个任务就会增加注意力的消耗。如果任务过于复杂且数量过多，注意力资源就会耗尽，从而影响整体的工作效率。</p><h3 id="你能解释什么是禁欲主义模式和节奏模式吗" tabindex="-1">你能解释什么是禁欲主义模式和节奏模式吗？ <a class="header-anchor" href="#你能解释什么是禁欲主义模式和节奏模式吗" aria-label="Permalink to &quot;你能解释什么是禁欲主义模式和节奏模式吗？&quot;">​</a></h3><p>禁欲主义模式是一种深度工作的极端方法，要求屏蔽所有可能的干扰信息，只专注于目标相关的事情。卡尔·纽波特认为这种方法能帮助我们在目标上深耕，例如在准备某个重要考试时，全力以赴只做相关的复习和准备。相比之下，节奏模式更适合日常生活，通过在每天的日程计划中找出整块时间来专注于重要任务，同时保持每天一定的深度工作习惯，逐步完成长期目标。节奏模式适合在日常生活和工作中需要处理琐事与紧急任务的情况下保持持续的专注力。</p><h3 id="如何通过清理屋子和工作台来提升专注力" tabindex="-1">如何通过清理屋子和工作台来提升专注力？ <a class="header-anchor" href="#如何通过清理屋子和工作台来提升专注力" aria-label="Permalink to &quot;如何通过清理屋子和工作台来提升专注力？&quot;">​</a></h3><p>清理屋子和工作台可以提升专注力，因为环境的整洁能减少视觉和心理干扰，帮助你更好地集中注意力。杂乱无章的环境会浪费大脑资源去处理不必要的信息干扰，使你难以专注在手头的重要任务上。通过清理物品、整理书桌、去掉过期的东西，你能创造一个有助于工作的环境，这样大脑可以更加专注地处理重要信息和任务。清理环境实际上是削减了非必要的负担，增强了注意力资源的有效利用。</p><h3 id="什么是链条法-如何运用链条法来保持长期动力" tabindex="-1">什么是链条法，如何运用链条法来保持长期动力？ <a class="header-anchor" href="#什么是链条法-如何运用链条法来保持长期动力" aria-label="Permalink to &quot;什么是链条法，如何运用链条法来保持长期动力？&quot;">​</a></h3><p>链条法是将长期任务视为链条，通过每日完成一定的任务量，在日历上画一个叉来表示任务的完成。随着时间推移，这些叉会连成一个锁链，这样可以直观地看到自己的努力成果，保持动力和督促自己不断前进。这种方法的关键在于每天都要排除其他不重要的干扰，腾出时间进行深度工作，从而坚持不懈地朝着长期目标迈进。通过链条法，你将会有更强的使命感和成就感，从而更容易克服拖延，保持对目标的热情和动力。</p><h2 id="_15时间管理1-时间难安排-用艾森豪威尔矩阵来管理" tabindex="-1">15时间管理1：时间难安排？用艾森豪威尔矩阵来管理 <a class="header-anchor" href="#_15时间管理1-时间难安排-用艾森豪威尔矩阵来管理" aria-label="Permalink to &quot;15时间管理1：时间难安排？用艾森豪威尔矩阵来管理&quot;">​</a></h2><h3 id="什么是艾森豪威尔矩阵-如何使用它来管理时间" tabindex="-1">什么是艾森豪威尔矩阵？如何使用它来管理时间？ <a class="header-anchor" href="#什么是艾森豪威尔矩阵-如何使用它来管理时间" aria-label="Permalink to &quot;什么是艾森豪威尔矩阵？如何使用它来管理时间？&quot;">​</a></h3><p>艾森豪威尔矩阵是一种时间管理工具，通过将任务按紧急性和重要性划分成四个象限来帮助人们合理安排时间。这四个象限包括：重要且紧急、重要但不紧急、不重要但紧急、不重要且不紧急。通过这种分类，我们可以优先处理重要且紧急的任务，安排时间做重要但不紧急的任务，减少或委托他人处理不重要但紧急的任务，尽量避免不重要且不紧急的任务。使用这种方法可以帮助我们更有效地统筹时间，提高工作效率。</p><h3 id="你如何定义和处理每天的三件最重要的事情" tabindex="-1">你如何定义和处理每天的三件最重要的事情？ <a class="header-anchor" href="#你如何定义和处理每天的三件最重要的事情" aria-label="Permalink to &quot;你如何定义和处理每天的三件最重要的事情？&quot;">​</a></h3><p>定义每天的三件最重要的事情时，可以将所有待办事项列出，挑选出其中最重要的三件并按优先级排列。每天专注于完成这三件事，如果有其他紧急且必须完成的任务，也应在完成这三件事的前提下适当插入处理。这个方法旨在确保每天都能完成对自己最重要的任务，从而提高效率，避免因杂事拖延造成的时间浪费。通过这个筛选过程，还能帮助我们识别并舍弃那些不重要的任务，使时间安排更加合理。</p><h3 id="如何舍弃不重要的任务以及合理拒绝他人的不合理请求" tabindex="-1">如何舍弃不重要的任务以及合理拒绝他人的不合理请求？ <a class="header-anchor" href="#如何舍弃不重要的任务以及合理拒绝他人的不合理请求" aria-label="Permalink to &quot;如何舍弃不重要的任务以及合理拒绝他人的不合理请求？&quot;">​</a></h3><p>舍弃不重要任务的一个有效方法是每天只做最重要的三件事。如果一周内某些任务一直未能进入每日三件事清单，那么这些任务可能是不重要的，可以舍弃。在拒绝他人不合理请求时，可以使用三个判断标准：这个人对你重不重要？这件事对他重不重要？你能不能做得好？至少有一个答案是肯定的才值得去做，否则应该坚决拒绝。学会拒绝那些占用你时间与精力的不合理请求，有助于专注于自己的重要任务，提升效率。</p><h3 id="如何通过减少紧急任务来实现理想的时间管理状态" tabindex="-1">如何通过减少紧急任务来实现理想的时间管理状态？ <a class="header-anchor" href="#如何通过减少紧急任务来实现理想的时间管理状态" aria-label="Permalink to &quot;如何通过减少紧急任务来实现理想的时间管理状态？&quot;">​</a></h3><p>减少紧急任务的关键在于事前规划和对任务的分解。根据SMART原则，将大任务分解为具体、可衡量、可操作、相关且实现的小任务，并为每个小任务设定提前的截止日期。这种做法不仅能按部就班完成任务，还能留出充足时间应对突发情况，从而避免任务变得紧急。理想的时间管理状态是任务尽可能地处于重要但不紧急的位置，这样既能保证任务的战略意义，又能控制好完成时间，减少时间压力。</p><h2 id="_16-时间管理2-日程难执行-你要学会列-非计划" tabindex="-1">16 时间管理2：日程难执行？你要学会列“非计划” <a class="header-anchor" href="#_16-时间管理2-日程难执行-你要学会列-非计划" aria-label="Permalink to &quot;16 时间管理2：日程难执行？你要学会列“非计划”&quot;">​</a></h2><h3 id="什么是非计划日程表-为什么与普通的计划日程表相比更有效" tabindex="-1">什么是非计划日程表，为什么与普通的计划日程表相比更有效？ <a class="header-anchor" href="#什么是非计划日程表-为什么与普通的计划日程表相比更有效" aria-label="Permalink to &quot;什么是非计划日程表，为什么与普通的计划日程表相比更有效？&quot;">​</a></h3><p>非计划日程表是一张以周为单位的日程表，而不是按天单独计划。其好处在于使日程安排更加全面和有整体性。非计划日程表填写的是所有你确定自己一定要做的事情，它是在确定了必须要做的事情之后，对于可支配的时间先做事情再填日程表。因此，这是一张逐渐被填满的表，也是你肯定做完了的表。相比之下，普通日程表填写的是你期待自己完成的完美目标，不一定可执行，且普通的日程表是先写日程后做事，最后未必能完成。</p><h3 id="非计划日程表的三步制作方法分别是什么" tabindex="-1">非计划日程表的三步制作方法分别是什么？ <a class="header-anchor" href="#非计划日程表的三步制作方法分别是什么" aria-label="Permalink to &quot;非计划日程表的三步制作方法分别是什么？&quot;">​</a></h3><p>非计划日程表的制作分为三步：第一步，要把这周确定必须做的事情列出来，填在周内相应位置。比如，有固定会议或其他已确定的事件。第二步，查看未被填满的时间，也就是本周的可支配时间，利用这些时间做能帮助你完成目标的事情，特别是那些重要的事情，完成后再在日程表上标记。第三步，填满表格后进行回顾评估，通过这张记录过的表了解自己的时间安排，如工作与生活的平衡以及改进的空间。</p><h3 id="非计划日程表如何在解决拖延症的问题上有效" tabindex="-1">非计划日程表如何在解决拖延症的问题上有效？ <a class="header-anchor" href="#非计划日程表如何在解决拖延症的问题上有效" aria-label="Permalink to &quot;非计划日程表如何在解决拖延症的问题上有效？&quot;">​</a></h3><p>非计划日程表能够帮助解决拖延症的问题，首先因为它避免了普通日程表的不切实际和难以执行，减少了因未完成任务带来的失望和焦虑。心理学家尼尔·费奥发明这一方法，发现很多客户因为日程表无法执行产生负面情绪。非计划日程表的逐渐被填满的特性让你更有成就感和控制感，先做然后记录的方法确保了实际成就，有利于逐步建立起行为习惯，减少拖延的发生。</p><h3 id="列出一个使用非计划日程表的实际例子-并描述其效果。如何帮助个体更好地安排时间" tabindex="-1">列出一个使用非计划日程表的实际例子，并描述其效果。如何帮助个体更好地安排时间？ <a class="header-anchor" href="#列出一个使用非计划日程表的实际例子-并描述其效果。如何帮助个体更好地安排时间" aria-label="Permalink to &quot;列出一个使用非计划日程表的实际例子，并描述其效果。如何帮助个体更好地安排时间？&quot;">​</a></h3><p>以学生小玉的例子为例。小玉根据自身情况及需要列出这周必须要做的事情，比如必要的休息、不同科目复习等。然后，她把必做的作业时间安排在了三个时段辅助进行，碰到突发事件如晚起了半小时，她主动调整午休时间以保证任务完成。这种弹性使她下午状态好、任务提前完成，甚至还帮忙安排了跑步和作文框架的书写。通过这种方法，小玉不仅完成了必做任务，还有时间进行额外活动，身心状态也更好。非计划日程表帮助她有效减少日程安排的僵化，提高安排的灵活性和完成功效。</p><h2 id="_17时间管理3-打破-时间错觉-建立良好的时间观" tabindex="-1">17时间管理3：打破“时间错觉”，建立良好的时间观 <a class="header-anchor" href="#_17时间管理3-打破-时间错觉-建立良好的时间观" aria-label="Permalink to &quot;17时间管理3：打破“时间错觉”，建立良好的时间观&quot;">​</a></h2><h3 id="为什么我们会对时间产生错觉-使得我们在进行预估时出现较大差异" tabindex="-1">为什么我们会对时间产生错觉, 使得我们在进行预估时出现较大差异? <a class="header-anchor" href="#为什么我们会对时间产生错觉-使得我们在进行预估时出现较大差异" aria-label="Permalink to &quot;为什么我们会对时间产生错觉, 使得我们在进行预估时出现较大差异?&quot;">​</a></h3><p>人对时间的感知是主观的，这种主观时间和客观的钟表时间可能相差很大。做喜欢的事情时感觉时间过得快，做不喜欢的事情时感觉时间过得慢。比如，看剧和刷微博时，我们常常会觉得没花多少时间，但实际上已经过去了几个小时。这种主观对时间的感受影响了我们对时间的判断，导致预估出现较大差异。</p><h3 id="如何通过日常训练提高我们的短期时间感知能力" tabindex="-1">如何通过日常训练提高我们的短期时间感知能力? <a class="header-anchor" href="#如何通过日常训练提高我们的短期时间感知能力" aria-label="Permalink to &quot;如何通过日常训练提高我们的短期时间感知能力?&quot;">​</a></h3><p>提高短期时间感知能力的方法有两个：首先是精确记录自己的时间，详细记录每件事的开始和结束时间，精确到分钟，这样有助于提升对时间的感知。第二个方法是有意识地给自己限定任务时间，比如收拾屋子时设定一个时间限制，通过多次实践来更好地预估自己完成任务所需的时间。</p><h3 id="什么是金巴多时间观念表-如何帮助我们建立良好的时间观" tabindex="-1">什么是金巴多时间观念表, 如何帮助我们建立良好的时间观? <a class="header-anchor" href="#什么是金巴多时间观念表-如何帮助我们建立良好的时间观" aria-label="Permalink to &quot;什么是金巴多时间观念表, 如何帮助我们建立良好的时间观?&quot;">​</a></h3><p>金巴多时间观念表将时间观分为六个维度：过去消极时间观、过去积极时间观、当下宿命主义时间观、当下享乐主义时间观、未来时间观和超未来时间观。这六个维度的时间观会影响一个人的生活、工作态度及行为表现。通过了解并强化积极的时间观（如过去积极时间观、当下享乐主义时间观和未来时间观），我们能够更好地规划和利用时间，从根本上解决时间管理和拖延问题。</p><h3 id="如何有效地建立和强化未来时间观以改善我们的时间管理" tabindex="-1">如何有效地建立和强化未来时间观以改善我们的时间管理? <a class="header-anchor" href="#如何有效地建立和强化未来时间观以改善我们的时间管理" aria-label="Permalink to &quot;如何有效地建立和强化未来时间观以改善我们的时间管理?&quot;">​</a></h3><p>建立和强化未来时间观的关键在于将未来的目标纳入现在的安排中。可以通过使用艾森豪威尔矩阵等工具来统筹时间，将重要但不紧急的事情放在计划的优先位置。多规划和着眼于将这些未来目标落实，逐步加强对未来的预见和准备，从而有效地管理和利用时间，避免拖延。</p><h2 id="_18第三周小结-不可控因素-来打扰-你该这样办" tabindex="-1">18第三周小结：“不可控因素”来打扰？你该这样办 <a class="header-anchor" href="#_18第三周小结-不可控因素-来打扰-你该这样办" aria-label="Permalink to &quot;18第三周小结：“不可控因素”来打扰？你该这样办&quot;">​</a></h2><h3 id="如何提升专注力" tabindex="-1">如何提升专注力？ <a class="header-anchor" href="#如何提升专注力" aria-label="Permalink to &quot;如何提升专注力？&quot;">​</a></h3><p><strong>提升专注力需要注意两个要素，一是有明确的注意对象，二是心理活动要有指向和集中</strong>。针对这些要素，可以采取两方面措施。首先，要时刻提醒自己当前注意力在哪里，并且希望要集中到哪里。其次，认识到注意力资源有限，务必清理冗余和低效的信息，这是做到真正高度专注的关键。</p><h3 id="如何进行有效的时间管理" tabindex="-1">如何进行有效的时间管理？ <a class="header-anchor" href="#如何进行有效的时间管理" aria-label="Permalink to &quot;如何进行有效的时间管理？&quot;">​</a></h3><p>有效的时间管理可以分为三个层次：对时间的整体统筹、对具体日程的规划、时间感知能力以及时间观的训练。首先，通过艾森豪威尔矩阵将任务按重要性和紧急性分为四类，并舍弃不重要的任务，减少紧急任务。在日程安排上使用非计划日程表，并通过回顾优化日程。最后，培养合理平衡的时间观，建立良好的时间感知能力。</p><h3 id="如何处理不可控因素对任务完成的干扰" tabindex="-1">如何处理不可控因素对任务完成的干扰？ <a class="header-anchor" href="#如何处理不可控因素对任务完成的干扰" aria-label="Permalink to &quot;如何处理不可控因素对任务完成的干扰？&quot;">​</a></h3><p>面对来自内外的不可控因素干扰，可以采取多种方法应对。例如，列清单放在每天必看见的地方以视觉提醒任务，公开承诺以增加责任感，集中代办事项和进度于一个地方增强路径依赖。此外，在和他人沟通，尤其是与领导交流时，选择重要任务进行沟通，避免不必要的冲突，保证任务顺利进行。</p><h3 id="如何竭尽全力和达到深度工作状态" tabindex="-1">如何竭尽全力和达到深度工作状态？ <a class="header-anchor" href="#如何竭尽全力和达到深度工作状态" aria-label="Permalink to &quot;如何竭尽全力和达到深度工作状态？&quot;">​</a></h3><p>竭尽全力意味着在截止时间内，尽力去做能改变结果的事情，不留遗憾。例如，申请出国留学时，看过改过所有文书，确保每个字都有意义；联系所有相关同学汇总面试问题并详尽解答。深度工作状态下，时间感会被弱化，注意力集中在工作上，例如写文章忘记晚饭时间，完全投入。通过掌握课程中的节奏模式，保持放松状态，有意识地进入深度工作。</p><h2 id="_19学会正确睡觉休息-有能量才能不拖延" tabindex="-1">19学会正确睡觉休息，有能量才能不拖延 <a class="header-anchor" href="#_19学会正确睡觉休息-有能量才能不拖延" aria-label="Permalink to &quot;19学会正确睡觉休息，有能量才能不拖延&quot;">​</a></h2><h3 id="什么是昼夜节律-它对我们的睡眠有何影响" tabindex="-1">什么是昼夜节律，它对我们的睡眠有何影响？ <a class="header-anchor" href="#什么是昼夜节律-它对我们的睡眠有何影响" aria-label="Permalink to &quot;什么是昼夜节律，它对我们的睡眠有何影响？&quot;">​</a></h3><p>昼夜节律是指人体内的一种生物钟机制，它调节并适应外部环境的变化，使我们的睡眠、激素分泌、体温和情绪呈现周期性变化。昼夜节律的主要周期约为24小时，即一个昼夜。例如褪黑素在晚上9点左右开始分泌，早上7点半左右停止，而体温在凌晨4点左右达到最低。因此，晚上11点到早上7点是我们睡眠的最佳时机，这时的睡眠效果最好。违反昼夜节律会导致精力不足，影响工作效率和健康状态。</p><h3 id="睡眠类型如何影响个人的最佳睡眠和工作节奏" tabindex="-1">睡眠类型如何影响个人的最佳睡眠和工作节奏？ <a class="header-anchor" href="#睡眠类型如何影响个人的最佳睡眠和工作节奏" aria-label="Permalink to &quot;睡眠类型如何影响个人的最佳睡眠和工作节奏？&quot;">​</a></h3><p>睡眠类型可大致分为早起鸟和夜猫子。早起鸟在白天工作时精力更好，晚上容易困倦；而夜猫子在早上起床困难，白天疲惫，但晚上工作效率高。这种差异由基因决定，是为了在人类进化过程中保证群落安全。因此，每个人的睡眠节律在普遍的昼夜节律基础上会有所偏移。例如，一个早起鸟适宜的睡眠时间可能是晚上9点到早上6点，而夜猫子可能是凌晨1点到早上9点。了解自己的睡眠类型有助于安排工作和休息，以达到最佳的工作效率和精力恢复效果。</p><h3 id="什么是r90睡眠法-它如何帮助我们提升睡眠质量" tabindex="-1">什么是R90睡眠法，它如何帮助我们提升睡眠质量？ <a class="header-anchor" href="#什么是r90睡眠法-它如何帮助我们提升睡眠质量" aria-label="Permalink to &quot;什么是R90睡眠法，它如何帮助我们提升睡眠质量？&quot;">​</a></h3><p>R90睡眠法是一种关注睡眠质量的策略，由英超曼联队的御用睡眠教练尼克提出。它建议以90分钟为一个睡眠周期来睡眠，每个周期包含入睡期、浅睡期、熟睡期、深睡期和快速眼动期。成年人每天需要4-5个周期（即6-7.5小时）的高质量睡眠。关键在于保持睡眠周期的完整，而不是睡眠时间的长短。打乱周期，如在熟睡期被打断，或日睡夜醒，都会使人感到疲倦。通过R90睡眠法，固定的起床时间和倒推的入睡时间可以帮助维持完整的睡眠周期，达到良好的精力恢复效果。</p><h3 id="可控修复器在日间精力恢复中起什么作用-如何利用它" tabindex="-1">可控修复器在日间精力恢复中起什么作用？如何利用它？ <a class="header-anchor" href="#可控修复器在日间精力恢复中起什么作用-如何利用它" aria-label="Permalink to &quot;可控修复器在日间精力恢复中起什么作用？如何利用它？&quot;">​</a></h3><p>可控修复器指的是在一天中特定时间段进行的短暂休息或小睡，可以帮助恢复精力。白天的两个修复时间段是午后1点到3点和傍晚5点到7点。这些时间段里，睡眠冲动较强，休息效果显著。根据个人情况，这时可以进行30分钟的小睡或90分钟的完整睡眠周期，也可以采取安静闭目养神的方式。如果长期感到劳累，不要依赖咖啡或红牛等提神饮料，而应利用这些时间段进行自然和有规律的休息，以避免打乱昼夜节律和造成更大的疲劳。</p><h2 id="_20学会正念冥想-跟你的情绪说-哦" tabindex="-1">20学会正念冥想，跟你的情绪说“哦” <a class="header-anchor" href="#_20学会正念冥想-跟你的情绪说-哦" aria-label="Permalink to &quot;20学会正念冥想，跟你的情绪说“哦”&quot;">​</a></h2><h3 id="什么是正念练习-它如何帮助解决拖延症" tabindex="-1">什么是正念练习，它如何帮助解决拖延症？ <a class="header-anchor" href="#什么是正念练习-它如何帮助解决拖延症" aria-label="Permalink to &quot;什么是正念练习，它如何帮助解决拖延症？&quot;">​</a></h3><p>正念练习是有目的、有意识地观察自己的一切，包括行动、情绪、想法和身体上的各种变化，并且对这些变化做到不加任何评价的接纳。正念练习的两个关键点是行为和意愿的统一、以及专注于当下。这些练习可以帮助你更好地控制自己的意识和行为，把注意力放在当下，从而缓解因未来可能的后果而产生的忧虑和恐惧。通过正念练习，你能减少拖延和焦虑，破除越拖延越焦虑的恶性循环。</p><h3 id="正念练习的四个要点是什么" tabindex="-1">正念练习的四个要点是什么？ <a class="header-anchor" href="#正念练习的四个要点是什么" aria-label="Permalink to &quot;正念练习的四个要点是什么？&quot;">​</a></h3><p>正念练习的四个要点分别是：第一，察觉自己、察觉环境；第二，专注于当下；第三，使自己的行为和意愿统一；第四，不加任何评价的接纳。通过察觉自己和环境，你可以更敏锐地觉察到自己和环境的变化。专注于当下能够让你把注意力放在现在的任务上，并缓解焦虑。行为和意愿的统一帮助你更好地协调身体和意识的行动。不加任何评价的接纳是对自己的一种包容，可以减少自我批评，缓解对未来的焦虑。</p><h3 id="什么是背森放松法-它的练习步骤是什么" tabindex="-1">什么是背森放松法，它的练习步骤是什么？ <a class="header-anchor" href="#什么是背森放松法-它的练习步骤是什么" aria-label="Permalink to &quot;什么是背森放松法，它的练习步骤是什么？&quot;">​</a></h3><p>背森放松法是由哈佛大学的身心医学专家贝森博士命名的放松练习方法。练习步骤如下：首先，选择一个较为安静、不被打扰的环境，坐着。然后，闭上眼睛，用几个呼吸的时间让肌肉和身体放松下来，注意每一次呼吸时身体的变化，同时在每次呼气时重复一个让你觉得舒服的字，比如安静、平和。整个过程不需要刻意控制呼吸和思绪，而是保持自然和开放的自我觉察，最终达到放松和集中注意力的效果。 躯体扫描法的目的是什么，它是如何进行的？</p><p>躯体扫描法的目的是通过关注身体的各个部位，达到身心的相互理解，进而让行为和意愿保持一致，缓解身体和精神的紧张与疲劳。练习时，你首先选择一个不被打扰的环境，坐着或躺下，并让自己松弛下来。然后将注意力扫描到身体的不同部位，从脚开始，逐步上移，感受每个部位的紧张、酸痛、放松等感觉。扫描的过程中不需要刻意压制杂念，而是自然地回到关注点。通常持续15分钟或更长，有助于缓解身体疲劳和焦虑。</p><h2 id="_21找到你的伙伴-和不拖延的人在一起" tabindex="-1">21找到你的伙伴，和不拖延的人在一起 <a class="header-anchor" href="#_21找到你的伙伴-和不拖延的人在一起" aria-label="Permalink to &quot;21找到你的伙伴，和不拖延的人在一起&quot;">​</a></h2><h3 id="什么是社群-以及它在对抗拖延症方面的作用是什么" tabindex="-1">什么是社群，以及它在对抗拖延症方面的作用是什么？ <a class="header-anchor" href="#什么是社群-以及它在对抗拖延症方面的作用是什么" aria-label="Permalink to &quot;什么是社群，以及它在对抗拖延症方面的作用是什么？&quot;">​</a></h3><p>社群是因为某个原因聚在一起的一群人，可以是线上的也可以是线下的。对抗拖延症，社群能够提供外部动力，通过群体影响和榜样的力量促进行为改变。人在社群中会更容易模仿他人的行为，这种模仿可以帮助拖延者更容易坚持完成目标。此外，社群还可以提供丰富的建议和信息资源，有助于更好地制定和调整计划，避免信息闭塞导致的拖延。举例来看，无论是为职业资格考试加入的QQ群，还是为了锻炼加入的夜跑俱乐部，都能通过社群的陪伴和榜样的力量带动成员不拖延。</p><h3 id="理想自我与现实自我之间的差距是如何影响拖延行为的" tabindex="-1">理想自我与现实自我之间的差距是如何影响拖延行为的？ <a class="header-anchor" href="#理想自我与现实自我之间的差距是如何影响拖延行为的" aria-label="Permalink to &quot;理想自我与现实自我之间的差距是如何影响拖延行为的？&quot;">​</a></h3><p><strong>理想自我是指一个人希望自己成为的样子，而现实自我则是实际情况。拖延的产生，往往是因为现实自我无法跟上理想自我。这种差距导致了行动和意愿的脱节，使人难以维持持续的积极行为</strong>。比如减肥时，理想自我可能是每天锻炼和健康饮食，但现实状况实际上难以保持，导致的吃零食和偷懒行为反过来又加强了对理想自我的想象。这种差距越大，拖延就越严重，甚至可能导致放弃目标。寻找和你有相同目标的社群，尤其是有榜样的社群，可以缩小这种差距。榜样的存在会让理想自我变得看得见和追得上，从而减少拖延。</p><h3 id="如何通过结对子的方式摆脱拖延" tabindex="-1">如何通过结对子的方式摆脱拖延？ <a class="header-anchor" href="#如何通过结对子的方式摆脱拖延" aria-label="Permalink to &quot;如何通过结对子的方式摆脱拖延？&quot;">​</a></h3><p>结对子是通过寻找一个或几个伙伴来共同完成任务，虽然每个人做的事可以完全无关，但共享同一个空间可以提升专注度，避免拖延。这种方式源于心理学的平行模仿，类似于孩子们的平行式玩耍。成年人在共同工作时，即使没有直接交流，也会受到同伴的存在影响而提高专注度。比如，在复习时找一个加班的朋友一起工作，或者在公共办公空间与其他自由职业者共处，都可以提高工作效率。同理，公司也可以将工作效率低的员工与高效率的员工安排在一起，互相带动，以减少拖延现象。</p><h3 id="什么是剪朋友-以及如何通过剪朋友减少拖延" tabindex="-1">什么是剪朋友，以及如何通过剪朋友减少拖延？ <a class="header-anchor" href="#什么是剪朋友-以及如何通过剪朋友减少拖延" aria-label="Permalink to &quot;什么是剪朋友，以及如何通过剪朋友减少拖延？&quot;">​</a></h3><p>剪朋友即是在朋友圈中筛选出会引导你拖延的人，并减少同他们的接触。密友五次元理论提到，一个人的财富和智慧是与他亲密交往的五个朋友的平均值，所以朋友圈的质量很大程度上决定了个人的成就。如果朋友散发出努力无用或者及时行乐的信息，或者总是要求你陪他们做不相关的事，这样的朋友会使你容易拖延。相反，那些能给你正向鼓励，帮助你找到解决方案的朋友则应被保留。减少不合适的朋友圈子，有助于减少拖延行为，并在积极圈子的影响下，提升自己的执行力和效率。</p><h2 id="_22拖延者的礼物-如何帮助他人不拖延" tabindex="-1">22拖延者的礼物，如何帮助他人不拖延 <a class="header-anchor" href="#_22拖延者的礼物-如何帮助他人不拖延" aria-label="Permalink to &quot;22拖延者的礼物，如何帮助他人不拖延&quot;">​</a></h2><h3 id="如何设立边界来应对拖延症" tabindex="-1">如何设立边界来应对拖延症? <a class="header-anchor" href="#如何设立边界来应对拖延症" aria-label="Permalink to &quot;如何设立边界来应对拖延症?&quot;">​</a></h3><p>设立边界涉及明确哪些是对方的事，哪些是你可以做的事，避免对方的拖延影响到你。这在心理学上被称为课题分离。著名的心理学家阿德勒提出了这一概念，旨在将个人需要自己面对的任务与应由他人完成的任务区分开来，尊重彼此的边界。明确了自己和他人的责任，是设立边界的第一步。例如，在应对孩子不写作业的问题上，家长需要明白写作业是孩子的任务，不应由家长代替完成。</p><h3 id="为何不能通过监控或威吓来解决拖延问题" tabindex="-1">为何不能通过监控或威吓来解决拖延问题? <a class="header-anchor" href="#为何不能通过监控或威吓来解决拖延问题" aria-label="Permalink to &quot;为何不能通过监控或威吓来解决拖延问题?&quot;">​</a></h3><p>监控和威吓都会增加对方的压力和不安全感，反而会让拖延者表现得更差，甚至逃避任务。例如，一位家长如果不断监控孩子的作业进度，并在孩子没按时完成任务时威吓他，孩子会感到巨大的压力和恐惧，可能会更抗拒完成作业，甚至回避与家长的交流。长此以往，孩子的依赖感和不自信会增强，形成恶性循环，不利于问题的解决。替代的方法是观观察、了解拖延背后的原因，并通过合作寻求解决方案。</p><h3 id="如何通过转变心态和合作来帮助拖延者" tabindex="-1">如何通过转变心态和合作来帮助拖延者? <a class="header-anchor" href="#如何通过转变心态和合作来帮助拖延者" aria-label="Permalink to &quot;如何通过转变心态和合作来帮助拖延者?&quot;">​</a></h3><p>转变心态首先要避免急于干涉，观察拖延者为什么拖延，找到真实的需求。以孩子拖延为例，家长发现孩子磨蹭可能是因为希望得到陪伴，而不单纯是不愿意做作业。这时，家长可以通过深度交流，了解孩子的真实需求，并寻求合作解决问题，例如，设定专门的陪伴时间，让孩子明确自己的任务，同时满足他的陪伴需求。在工作中也是如此，理解同事的挑战，通过合作而非监工来解决问题，能更有效地提高任务的完成度。</p><h2 id="_23结语彩蛋-告别拖延症-人生新开始" tabindex="-1">23结语彩蛋：告别拖延症，人生新开始 <a class="header-anchor" href="#_23结语彩蛋-告别拖延症-人生新开始" aria-label="Permalink to &quot;23结语彩蛋：告别拖延症，人生新开始&quot;">​</a></h2><h3 id="黄河清在学二胡的过程中遇到了哪些困难" tabindex="-1">黄河清在学二胡的过程中遇到了哪些困难？ <a class="header-anchor" href="#黄河清在学二胡的过程中遇到了哪些困难" aria-label="Permalink to &quot;黄河清在学二胡的过程中遇到了哪些困难？&quot;">​</a></h3><p>黄河清在学二胡过程中遇到的困难包括：首先，他发现自己无法分辨音准，这使得老师教的两个音在他耳中听起来是一样的。其次，因为他练习时间长且手劲较大，导致二胡的弦经常被他拉断，不仅增加了调音的复杂性，还加大了学习成本。这些问题让他感到挫败，最终不得不放弃了学二胡的计划。</p><h3 id="通过学习二胡这段经历-黄河清得到了哪些收获和反思" tabindex="-1">通过学习二胡这段经历，黄河清得到了哪些收获和反思？ <a class="header-anchor" href="#通过学习二胡这段经历-黄河清得到了哪些收获和反思" aria-label="Permalink to &quot;通过学习二胡这段经历，黄河清得到了哪些收获和反思？&quot;">​</a></h3><p>通过学习二胡，黄河清得到了三个主要的收获和反思。第一，他对自己无法在台上秀乐器这件事情彻底释怀了，不再有遗憾，因为他已经尽力尝试过。第二，他意识到自己在音乐上确实可能没有天赋，但是也找到了更能满足他表演欲望的方向，如辩论、演讲和话剧，这些领域更能发挥他的长处。第三，他学会了接受自己并不完美的事实，这让他内心更加平和，逐步建立了属于自己的小世界，开始做一个他喜欢且认可的自己。</p><h3 id="黄河清是如何将放弃学二胡的经历转化为积极的生活态度的" tabindex="-1">黄河清是如何将放弃学二胡的经历转化为积极的生活态度的？ <a class="header-anchor" href="#黄河清是如何将放弃学二胡的经历转化为积极的生活态度的" aria-label="Permalink to &quot;黄河清是如何将放弃学二胡的经历转化为积极的生活态度的？&quot;">​</a></h3><p>黄河清通过这段经历学会了接受并不完美的自己，理解到并不是所有努力都一定有回报，但没必要因此停止尝试。他把放弃学二胡后腾出的时间投入到自己更擅长并且更感兴趣的活动中，如参加话剧社，增强语言技能。他在巴黎留学期间利用这些优势，在商学院和职场中取得了出色的成绩。最终，他意识到不拖延的重要性，主动探索并找到适合自己的方向，展现了他积极面对生活挑战的态度。</p>',192)]))}const q=e(o,[["render",i]]);export{b as __pageData,q as default};
